class Solution {
    public int integerReplacement(int n) {
        int operations = 0;
        while (n != 1) {
            if (n % 2 == 0) {
                n /= 2;
            } else {
                if (n == 3) {
                    n = 2;
                } else {
                    n += (n % 2 == 1) ? -1 : 1;
                }
            }
            operations++;
        }
        return operations;
    }
}
